<template>
  <div class="page-push">
    <SpFilterForm :model="params" @onSearch="onSearch" @onReset="onReset">
      <SpFilterFormItem prop="status" label="推播狀態:">
        <el-select v-model="params.status" placeholder="全部狀態" clearable @change="onSearch">
          <el-option
            v-for="(item, index) in statusList"
            :key="index"
            :label="item.name"
            :value="item.value"
          />
        </el-select>
      </SpFilterFormItem>
    </SpFilterForm>

    <div class="list">
      <el-table v-loading="loading" border :data="tableList" element-loading-text="數據加載中">
        <el-table-column prop="request_params" width="200" label="請求參數">
          <template slot-scope="scope">
            <div style="max-height: 200px; overflow: auto;">
              {{ scope.row.request_params }}
            </div>
          </template>
        </el-table-column>
        <el-table-column prop="response_data" width="500" label="響應參數">
          <template slot-scope="scope">
            <div style="max-height: 200px; overflow: auto;">
              {{ scope.row.response_data }}
            </div>
          </template>
        </el-table-column>
        <el-table-column prop="http_status_code" label="回應訊息" />
        <el-table-column label="推播狀態">
          <template slot-scope="scope">
            <el-tag v-if="scope.row.status === '0'" type="success">
              成功
            </el-tag>
            <el-tag v-else type="danger">
              失敗
            </el-tag>
          </template>
        </el-table-column>
        <el-table-column prop="push_time" width="100" label="推送时间" />
        <el-table-column prop="cost_time" label="耗時(毫秒)" />
        <el-table-column prop="retry_times" label="重試次數" />
        <el-table-column prop="type" label="介面類型" />
        <el-table-column label="操作">
          <template slot-scope="scope">
            <el-button :disabled="scope.row.status === '0'" :loading="scope.row.loading" type="warning" size="mini" icon="ecx-icon icon-zhongzhi" @click="handleRepeatPush(scope.row)">
              重推
            </el-button>
          </template>
        </el-table-column>
      </el-table>
    </div>

    <div class="content-padded content-center">
      <el-pagination
        background
        layout="total, sizes, prev, pager, next, jumper"
        :current-page.sync="page.pageIndex"
        :page-sizes="[10, 20, 50]"
        :total="page.total"
        :page-size="page.pageSize"
        @current-change="onCurrentChange"
        @size-change="onSizeChange"
      />
    </div>
  </div>
</template>

<script>
import mixin, { pageMixin } from '@/mixins'
import {setPushLogs} from "@/api/company";
export default {
  name: 'SettingPush',
  components: {},
  mixins: [mixin, pageMixin],
  props: {},
  data() {
    return {
      initialParams: {
        status: null
      },
      params: {
        status: null
      },
      statusList: [
        { name: '成功', value: 0 },
        { name: '失败', value: 1 }
      ],
      loading: false,
      tableList: []
    };
  },
  computed: {},
  watch: {},
  created() {
    this.fetchList()
  },
  methods: {
    onSearch() {
      this.page.pageIndex = 1
      this.$nextTick(() => {
        this.fetchList()
      })
    },
    onReset() {
      this.params = { ...this.initialParams }
      this.onSearch()
    },
    async fetchList() {
      this.loading = true
      const { pageIndex: page, pageSize } = this.page
      let params = {
        page,
        pageSize,
        ...this.params
      }
      const { list, total_count } = await this.$api.company.getPushLogs(params)
      this.tableList = (list || []).map(item => {
        return {
          ...item,
          loading: false
        }
      })
      this.page.total = total_count
      this.loading = false
    },
    async handleRepeatPush(row) {
      row.loading = true
      this.$api.company.setPushLogs({
        id: row.id
      }).then(() => {
        this.fetchList()
        this.$message({
          type: 'success',
          message: '重推成功'
        })
      }).finally(() => {
        row.loading = false
      })
    }
  }
};
</script>

<style lang="scss" scoped>
  .page-push{
    .list{ padding-top: 10px;}
  }
</style>
